  'useCase.marketResearch.desc': { en: 'Consumer insights & trends', zh: '消费者洞察和趋势', es: 'Insights del consumidor y tendencias', fr: 'Insights consommateurs et tendances', de: 'Verbrauchereinblicke und Trends', ja: '消費者インサイトとトレンド', ko: '소비자 인사이트 및 트렌드', pt: 'Insights do consumidor e tendências', ar: 'رؤى المستهلكين والاتجاهات', hi: 'उपभोक्ता अंतर्दृष्टि और रुझान', ru: 'Потребительские инсайты и тренды', it: 'Insight dei consumatori e tendenze' },
